import React, { useState } from 'react';
import api from '../services/api';

export default function PromoPanel() {
  const user    = JSON.parse(localStorage.getItem('zipride_user') || '{}');
  const role    = user.role || 'PASSENGER';
  const isAdmin = role === 'ADMIN';

  const [createForm, setCreateForm] = useState({
    code:'', description:'', discountType:'PERCENTAGE', discountValue:'20',
    maxDiscountAmount:'100', minFareRequired:'50', maxUsageCount:'100',
    validFrom:'', validUntil:'', status:'ACTIVE'
  });
  const [applyForm,    setApplyForm]    = useState({ promoCode:'', passengerId:'1', originalFare:'200' });
  const [createResult, setCreateResult] = useState(null);
  const [applyResult,  setApplyResult]  = useState(null);
  const [allPromos,    setAllPromos]    = useState(null);
  const [loading,      setLoading]      = useState(false);

  const createPromo = async e => {
    e.preventDefault(); setCreateResult(null);
    try {
      const { data } = await api.post('/api/promo/create', {
        ...createForm,
        discountValue:     parseFloat(createForm.discountValue),
        maxDiscountAmount: createForm.discountType === 'PERCENTAGE' ? parseFloat(createForm.maxDiscountAmount) : null,
        minFareRequired:   parseFloat(createForm.minFareRequired),
        maxUsageCount:     parseInt(createForm.maxUsageCount),
      });
      setCreateResult({ success:true, data });
    } catch (err) { setCreateResult({ success:false, message: err.response?.data?.message || 'Error' }); }
  };

  const applyPromo = async e => {
    e.preventDefault(); setLoading(true); setApplyResult(null);
    try {
      const { data } = await api.post('/api/promo/apply', {
        promoCode:    applyForm.promoCode,
        passengerId:  parseInt(applyForm.passengerId),
        originalFare: parseFloat(applyForm.originalFare)
      });
      setApplyResult(data);
    } catch (err) { setApplyResult({ message: err.response?.data?.message || 'Error', valid:false }); }
    finally { setLoading(false); }
  };

  const fetchAll = async () => {
    try { const { data } = await api.get('/api/promo/all'); setAllPromos(data); } catch {}
  };

  const fetchActive = async () => {
    try { const { data } = await api.get('/api/promo/active'); setAllPromos(data); } catch {}
  };

  return (
    <>
      {/* ── ADMIN ONLY: Create Promo Code ───────────────────────── */}
      {isAdmin && (
        <div className="panel">
          <div className="panel-header">
            <h3>Create Promo Code</h3>
            <span className="badge">ADMIN only · POST /api/promo/create</span>
          </div>
          <div className="panel-body">
            {createResult && (
              <div className={`alert ${createResult.success ? 'alert-success' : 'alert-error'}`}>
                {createResult.success ? `✓ Promo "${createResult.data.code}" created!` : `✗ ${createResult.message}`}
              </div>
            )}
            <form onSubmit={createPromo}>
              <div className="form-row">
                <div className="form-group"><label>Promo Code</label><input placeholder="SAVE20" value={createForm.code} onChange={e => setCreateForm({...createForm, code: e.target.value.toUpperCase()})} /></div>
                <div className="form-group"><label>Description</label><input placeholder="20% off your ride" value={createForm.description} onChange={e => setCreateForm({...createForm, description: e.target.value})} /></div>
              </div>
              <div className="form-row">
                <div className="form-group"><label>Discount Type</label>
                  <select value={createForm.discountType} onChange={e => setCreateForm({...createForm, discountType: e.target.value})}>
                    <option value="PERCENTAGE">Percentage (%)</option>
                    <option value="FLAT">Flat (₹)</option>
                  </select>
                </div>
                <div className="form-group"><label>Discount Value</label><input type="number" placeholder="20" value={createForm.discountValue} onChange={e => setCreateForm({...createForm, discountValue: e.target.value})} /></div>
                {createForm.discountType === 'PERCENTAGE' &&
                  <div className="form-group"><label>Max Discount Cap (₹)</label><input type="number" placeholder="100" value={createForm.maxDiscountAmount} onChange={e => setCreateForm({...createForm, maxDiscountAmount: e.target.value})} /></div>
                }
              </div>
              <div className="form-row">
                <div className="form-group"><label>Min Fare (₹)</label><input type="number" placeholder="50" value={createForm.minFareRequired} onChange={e => setCreateForm({...createForm, minFareRequired: e.target.value})} /></div>
                <div className="form-group"><label>Max Usage</label><input type="number" placeholder="100" value={createForm.maxUsageCount} onChange={e => setCreateForm({...createForm, maxUsageCount: e.target.value})} /></div>
              </div>
              <div className="form-row">
                <div className="form-group"><label>Valid From</label><input type="datetime-local" value={createForm.validFrom} onChange={e => setCreateForm({...createForm, validFrom: e.target.value})} /></div>
                <div className="form-group"><label>Valid Until</label><input type="datetime-local" value={createForm.validUntil} onChange={e => setCreateForm({...createForm, validUntil: e.target.value})} /></div>
              </div>
              <button className="btn-action" type="submit">Create Promo Code</button>
            </form>
          </div>
        </div>
      )}

      {/* ── PASSENGER + ADMIN: Apply Promo Code ─────────────────── */}
      <div className="panel">
        <div className="panel-header">
          <h3>Apply Promo Code</h3>
          <span className="badge">POST /api/promo/apply</span>
        </div>
        <div className="panel-body">
          <form onSubmit={applyPromo}>
            <div className="form-row">
              <div className="form-group"><label>Promo Code</label><input placeholder="SAVE20" value={applyForm.promoCode} onChange={e => setApplyForm({...applyForm, promoCode: e.target.value})} /></div>
              <div className="form-group"><label>Passenger ID</label><input placeholder="1" value={applyForm.passengerId} onChange={e => setApplyForm({...applyForm, passengerId: e.target.value})} /></div>
              <div className="form-group"><label>Original Fare (₹)</label><input type="number" placeholder="200" value={applyForm.originalFare} onChange={e => setApplyForm({...applyForm, originalFare: e.target.value})} /></div>
            </div>
            <button className="btn-action" type="submit" disabled={loading}>
              {loading && <span className="spinner" />} Apply Promo
            </button>
          </form>
          {applyResult && (
            <div className="result-card">
              <h4>Promo Result</h4>
              <div className="result-row"><span className="rk">Valid</span>
                <span className={`rv ${applyResult.valid ? 'success' : 'error'}`}>{applyResult.valid ? '✓ Yes' : '✗ No'}</span>
              </div>
              <div className="result-row"><span className="rk">Message</span><span className="rv" style={{ fontSize:13 }}>{applyResult.message || applyResult.validationMessage}</span></div>
              {applyResult.valid && <>
                <div className="result-row"><span className="rk">Original Fare</span><span className="rv">₹{applyResult.originalFare}</span></div>
                <div className="result-row"><span className="rk">Discount</span><span className="rv success">−₹{applyResult.discountAmount?.toFixed(2)}</span></div>
                <div className="result-row"><span className="rk">Final Fare</span><span className="rv highlight">₹{applyResult.finalFare?.toFixed(2)}</span></div>
              </>}
            </div>
          )}
        </div>
      </div>

      {/* ── View Promos: ADMIN sees all, PASSENGER sees active only ─ */}
      <div className="panel">
        <div className="panel-header">
          <h3>{isAdmin ? 'All Promo Codes' : 'Active Promo Codes'}</h3>
          <span className="badge">{isAdmin ? 'GET /api/promo/all' : 'GET /api/promo/active'}</span>
        </div>
        <div className="panel-body">
          <button className="btn-action" onClick={isAdmin ? fetchAll : fetchActive}>
            Load {isAdmin ? 'All' : 'Active'} Codes
          </button>
          {allPromos && (
            <div style={{ marginTop:20 }}>
              {allPromos.length === 0
                ? <p style={{ color:'var(--text-muted)', fontSize:13 }}>No promo codes found.</p>
                : <table className="data-table">
                    <thead><tr><th>Code</th><th>Type</th><th>Value</th><th>Min Fare</th><th>Usage</th><th>Status</th></tr></thead>
                    <tbody>{allPromos.map(p => (
                      <tr key={p.id}>
                        <td style={{ color:'var(--gold)', fontWeight:600 }}>{p.code}</td>
                        <td>{p.discountType}</td>
                        <td>{p.discountType === 'PERCENTAGE' ? `${p.discountValue}%` : `₹${p.discountValue}`}</td>
                        <td>₹{p.minFareRequired}</td>
                        <td>{p.usageCount}/{p.maxUsageCount}</td>
                        <td><span className={`badge-status ${p.status === 'ACTIVE' ? 'badge-available' : 'badge-offline'}`}>{p.status}</span></td>
                      </tr>
                    ))}</tbody>
                  </table>
              }
            </div>
          )}
        </div>
      </div>
    </>
  );
}
